SELECT ForecastBudgetApeE17.[Trademark Code], ForecastBudgetApeE17.[Sales Season Code], ForecastBudgetApeE17.[Salesperson Code], ForecastBudgetApeE17.SalesPersonName, ForecastBudgetApeE17.[Geographical Zone], ForecastBudgetApeE17.CustomerCode, ForecastBudgetApeE17.CustomerName, ForecastBudgetApeE17.CustomerGeorgraficalZone, ForecastBudgetApeE17.CustomerGeorgraficalZoneDescription, ForecastBudgetApeE17.CustomerGeorgraficalZone2, ForecastBudgetApeE17.CustomerGeorgraficalZone2Description, ForecastBudgetApeE17.City, ForecastBudgetApeE17.[Current Risk], ForecastBudgetApeE17.[Authorized Stores Number], Sum(ForecastBudgetApeE17.NewLineBudgetQty) AS NewLineBudgetQty, ForecastBudgetApeE17.NewLineBudgetAmount AS NewLineBudgetAmount, ForecastBudgetApeE17.NewLineRevisedBudgetQty AS NewLineRevisedBudgetQty, ForecastBudgetApeE17.NewLineRevisedBudgetAmount AS NewLineRevisedBudgetAmount, ForecastBudgetApeE17.NewCurrentBudgetQty AS NewCurrentBudgetQty, ForecastBudgetApeE17.NewPreviousCorrSeasonQty AS NewPreviousCorrSeasonQty, ForecastBudgetApeE17.NewPreviousCorrSeasonAmount AS NewPreviousCorrSeasonAmount, ForecastBudgetApeE17.ActualQty AS ActualQty, ForecastBudgetApeE17.ActualAmount AS ActualAmount, ForecastBudgetApeE17.NewForecastQty AS NewForecastQty, ForecastBudgetApeE17.NewForecastAmount AS NewForecastAmount, ForecastBudgetApeE17.NewAdjustedForecastQty AS NewAdjustedForecastQty, ForecastBudgetApeE17.NewAdjustedForecastAmount AS NewAdjustedForecastAmount, Min(ForecastBudgetApeE17.BudgetLineStatus) AS BudgetLineStatus, Max(ForecastBudgetApeE17.NoBuyReaon) AS NoBuyReaon
FROM ForecastBudgetApeE17
GROUP BY ForecastBudgetApeE17.[Trademark Code], ForecastBudgetApeE17.[Sales Season Code], ForecastBudgetApeE17.[Salesperson Code], ForecastBudgetApeE17.SalesPersonName, ForecastBudgetApeE17.[Geographical Zone], ForecastBudgetApeE17.CustomerCode, ForecastBudgetApeE17.CustomerName, ForecastBudgetApeE17.CustomerGeorgraficalZone, ForecastBudgetApeE17.CustomerGeorgraficalZoneDescription, ForecastBudgetApeE17.CustomerGeorgraficalZone2, ForecastBudgetApeE17.CustomerGeorgraficalZone2Description, ForecastBudgetApeE17.City, ForecastBudgetApeE17.[Current Risk], ForecastBudgetApeE17.[Authorized Stores Number], ForecastBudgetApeE17.NewLineBudgetAmount, ForecastBudgetApeE17.NewLineRevisedBudgetQty, ForecastBudgetApeE17.NewLineRevisedBudgetAmount, ForecastBudgetApeE17.NewCurrentBudgetQty, ForecastBudgetApeE17.NewPreviousCorrSeasonQty, ForecastBudgetApeE17.NewPreviousCorrSeasonAmount, ForecastBudgetApeE17.ActualQty, ForecastBudgetApeE17.ActualAmount, ForecastBudgetApeE17.NewForecastQty, ForecastBudgetApeE17.NewForecastAmount, ForecastBudgetApeE17.NewAdjustedForecastQty, ForecastBudgetApeE17.NewAdjustedForecastAmount;

